-- DPR final seed import for live dev.
-- Use pgAdmin Query Tool > Open File, or psql -f. Do not paste this whole file into the editor.
-- Preserves real registered users/accounts/sessions/verifications.
-- Removes only previous DPR seed rows and the known dummy reference rows.

ROLLBACK;

SET statement_timeout = 0;
SET lock_timeout = 0;
SET idle_in_transaction_session_timeout = 0;
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SELECT pg_catalog.set_config('search_path', '', false);
SET check_function_bodies = false;
SET xmloption = content;
SET client_min_messages = warning;
SET row_security = off;

BEGIN;

DO $$
BEGIN
  IF EXISTS (
    SELECT 1
    FROM public.digital_property
    WHERE id BETWEEN 1 AND 100
      AND property_name NOT LIKE 'Seed DPR - %'
  ) THEN
    RAISE EXCEPTION 'Refusing DPR seed import: public.digital_property already has non-seed rows with ids 1-100. This fixed-id dump would collide. Stop and use a remapped import.';
  END IF;
END
$$;

DELETE FROM public.audit_event
WHERE actor_user_id LIKE 'seed-user-%'
   OR target_user_id LIKE 'seed-user-%'
   OR id LIKE 'seed-audit-%'
   OR (
     entity_type = 'DIGITAL_PROPERTY'
     AND entity_id IN (
       SELECT id::text
       FROM public.digital_property
       WHERE property_name LIKE 'Seed DPR - %'
     )
   );

DELETE FROM public.social_digital_property_details d
USING public.digital_property p
WHERE d.digital_property_id = p.id
  AND p.property_name LIKE 'Seed DPR - %';

DELETE FROM public.website_digital_property_details d
USING public.digital_property p
WHERE d.digital_property_id = p.id
  AND p.property_name LIKE 'Seed DPR - %';

DELETE FROM public.digital_property_country d
USING public.digital_property p
WHERE d.digital_property_id = p.id
  AND p.property_name LIKE 'Seed DPR - %';

DELETE FROM public.digital_property
WHERE property_name LIKE 'Seed DPR - %';

DELETE FROM public.user_role_country_scope
WHERE user_role_user_id LIKE 'seed-user-%';

DELETE FROM public.user_role
WHERE user_id LIKE 'seed-user-%';

DELETE FROM public.brand_country_availability
WHERE brand_id LIKE 'seed-brand-%'
   OR country_id LIKE 'seed-country-%';

DELETE FROM public.brand
WHERE id LIKE 'seed-brand-%';

DELETE FROM public.agency
WHERE id LIKE 'seed-agency-%';

DELETE FROM public.country
WHERE id LIKE 'seed-country-%'
   OR name = 'DummyCountry';

DELETE FROM public.region
WHERE id LIKE 'seed-region-%'
   OR name = 'Dummy';

DELETE FROM public."user"
WHERE id LIKE 'seed-user-%'
   OR email LIKE '%@dpr-seed.test';

