SELECT pg_catalog.setval(
  'public.digital_property_id_seq',
  GREATEST(
    COALESCE((SELECT MAX(id) FROM public.digital_property), 0),
    COALESCE((SELECT last_value FROM public.digital_property_id_seq), 0)
  ),
  true
);

COMMIT;

SELECT 'seed_users' AS check_name, COUNT(*) AS count FROM public."user" WHERE id LIKE 'seed-user-%' OR email LIKE '%@dpr-seed.test'
UNION ALL SELECT 'seed_user_roles', COUNT(*) FROM public.user_role WHERE user_id LIKE 'seed-user-%'
UNION ALL SELECT 'regions', COUNT(*) FROM public.region WHERE id LIKE 'seed-region-%'
UNION ALL SELECT 'countries', COUNT(*) FROM public.country WHERE id LIKE 'seed-country-%'
UNION ALL SELECT 'brands', COUNT(*) FROM public.brand WHERE id LIKE 'seed-brand-%'
UNION ALL SELECT 'agencies', COUNT(*) FROM public.agency WHERE id LIKE 'seed-agency-%'
UNION ALL SELECT 'digital_properties', COUNT(*) FROM public.digital_property WHERE property_name LIKE 'Seed DPR - %'
UNION ALL SELECT 'seed_audit_events', COUNT(*) FROM public.audit_event WHERE actor_user_id LIKE 'seed-user-%' OR target_user_id LIKE 'seed-user-%' OR id LIKE 'seed-audit-%';
